// v1.1：從 allReadItems 迭代 + textMap 查表 + filterPrintable 過濾亂碼

const items = $input.all();
const allReadItems = $('Read 知識文件').all();

function filterPrintable(text) {
  if (!text || typeof text !== 'string') return '';
  const printableMatches = text.match(/[\u4e00-\u9fff\u3000-\u303f\uff00-\uffefa-zA-Z0-9\s.,!?;:()\[\]{}\-+="'\/_*&%$#@~|<>\n]/g);
  const ratio = printableMatches ? printableMatches.length / text.length : 0;
  return ratio > 0.7 ? text : '';
}

const textMap = new Map();
for (const it of items) {
  const fn = it.binary?.data?.fileName;
  if (!fn) continue;
  const t = it.json?.text ?? it.json?.data;
  if (t != null) textMap.set(fn, String(t));
}

const chunks = [];
const stats = { totalFiles: allReadItems.length, indexed: 0, skipped: 0, totalChunks: 0 };

for (let i = 0; i < allReadItems.length; i++) {
  const readItem = allReadItems[i];
  if (!readItem?.binary?.data) { stats.skipped++; continue; }

  const fileName = readItem.json.fileName || ('unknown-' + (i + 1));
  const rawText = textMap.get(fileName) ?? '';
  const cleanText = filterPrintable(rawText);

  if (!cleanText || cleanText.length < 50) {
    stats.skipped++;
    continue;
  }

  stats.indexed++;
  const size = 500, overlap = 50;
  for (let p = 0; p < cleanText.length; p += (size - overlap)) {
    const chunk = cleanText.substring(p, p + size).trim();
    if (chunk.length < 50) continue;
    chunks.push({ source: fileName, pos: p, text: chunk, indexedAt: new Date().toISOString() });
  }
}

stats.totalChunks = chunks.length;
const jsonl = chunks.map(c => JSON.stringify(c)).join('\n');

return [{
  json: { chunkCount: chunks.length, indexPath: '/files/shared/knowledge-index/knowledge-index.jsonl', _stats: stats },
  binary: { data: { data: Buffer.from(jsonl).toString('base64'), mimeType: 'application/jsonl', fileName: 'knowledge-index.jsonl' } }
}];

// 關鍵字 match + AI 生答（窮人版 RAG）
const GEMINI_API_KEY = '__GEMINI_API_KEY__';
const question = $('Webhook: kb-ask').first().json.body?.question || $('Webhook: kb-ask').first().json.query?.question || '請告訴我你能回答什麼？';

// 讀 JSONL 索引
const indexFile = $input.first().binary?.data?.data || '';
const jsonlText = Buffer.from(indexFile, 'base64').toString('utf-8');
const chunks = jsonlText.split('\n').filter(l => l).map(l => JSON.parse(l));

// 關鍵字 score（簡化版：question 的字 vs chunk 的 overlap）
const qWords = question.split(/[\s，。？！,\.\?]/).filter(w => w.length >= 2);
const scored = chunks.map(c => ({
  ...c,
  score: qWords.reduce((s, w) => s + (c.text.includes(w) ? 1 : 0), 0)
})).filter(c => c.score > 0).sort((a, b) => b.score - a.score).slice(0, 5);

if (scored.length === 0) {
  return [{ json: { answer: '知識庫內找不到相關內容。請改問其他問題或重建索引。', sources: [], question } }];
}

// 餵給 Gemini
const context = scored.map((c, i) => '[' + (i+1) + '] (' + c.source + ')\n' + c.text).join('\n\n');
const prompt = '你是企業知識庫問答助手。根據下面 context 回答用戶問題（繁體中文）。如果 context 不足以回答，誠實說「資料庫內無此資訊」。每段答覆引用來源編號 [1] [2] 等。\n\n<question>' + question + '</question>\n\n<context>\n' + context + '\n</context>';

let answer = '';
try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent',
    headers: { 'Content-Type': 'application/json', 'x-goog-api-key': GEMINI_API_KEY },
    body: {
      contents: [{ role: 'user', parts: [{ text: prompt }] }],
      generationConfig: { temperature: 0.4, maxOutputTokens: 800, thinkingConfig: { thinkingBudget: 0 } }
    },
    json: true,
    timeout: 60000
  });
  answer = response.candidates?.[0]?.content?.parts?.[0]?.text || 'AI 無回應';
} catch (err) {
  answer = '查詢失敗：' + (err.message || err);
}

return [{
  json: {
    question, answer,
    sources: scored.map((c, i) => ({ ref: i+1, file: c.source, snippet: c.text.substring(0, 100) }))
  }
}];

