  <button id="askBtn" onclick="ask()">問</button>

  <div id="result" class="result"></div>

  <div class="footer">
    <strong>使用前確認</strong>：① 已跑過 Part A（建索引）② 此 workflow Active = ON（不然 webhook 不接受 production POST）<br>
    POST endpoint：<code>/webhook/kb-ask</code> · GET 此頁面：<code>/webhook/kb-ui</code>
  </div>
</div>

<script>
function setQ(s){document.getElementById('q').value=s;}
function escapeHtml(s){return String(s).replace(/[<>&"']/g,c=>({'<':'&lt;','>':'&gt;','&':'&amp;','"':'&quot;',"'":'&#39;'}[c]))}

async function ask(){
  const q=document.getElementById('q').value.trim();
  if(!q){return;}
  const btn=document.getElementById('askBtn');
  const result=document.getElementById('result');
  btn.disabled=true;btn.textContent='思考中...';
  result.classList.add('show');
  result.innerHTML='<div class="loading">查詢知識庫中...</div>';

  try{
    const r=await fetch('/webhook/kb-ask',{
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body:JSON.stringify({question:q})
    });
    if(!r.ok){throw new Error('HTTP '+r.status+' — 確認 #12 workflow Active = ON');}
    const data=await r.json();

    let html='<div class="result-q"><strong>Q：</strong>'+escapeHtml(data.question||q)+'</div>';
    html+='<div class="result-a">'+escapeHtml(data.answer||'無答覆').replace(/\\n/g,'<br>')+'</div>';
    if(data.sources&&data.sources.length){
      html+='<div class="sources"><div class="sources-label">引用來源</div>';
      data.sources.forEach(s=>{
        html+='<div class="source-item"><span class="source-ref">'+s.ref+'</span><span class="source-file">'+escapeHtml(s.file)+'</span><br>';
        html+='<span style="margin-left:32px;color:#bcb8ae;">'+escapeHtml(s.snippet||'')+'</span></div>';
      });
      html+='</div>';
    }
    result.innerHTML=html;
  }catch(e){
    result.innerHTML='<div class="error"><strong>錯誤：</strong>'+escapeHtml(e.message)+'</div>';
  }
  btn.disabled=false;btn.textContent='問';
}

document.getElementById('q').addEventListener('keydown',e=>{
  if((e.ctrlKey||e.metaKey)&&e.key==='Enter'){ask();}
});
</script>
